pipeline {
  agent any
  stages {
    stage('Lint') {
      steps { sh 'npm run lint -- --max-warnings 0' }
    }
    stage('Test') {
      steps { sh 'npm test -- --ci' }
      post { always { junit 'reports/jest/*.xml' } }
    }
    stage('Build') {
      steps {
        sh 'npm run build'
        stash name: 'dist', includes: 'dist/**'
      }
    }
    stage('Deploy') {
      when { branch 'main' }
      steps {
        unstash 'dist'
        sh './scripts/deploy.sh'
      }
    }
  }
}

// vars/buildAndPush.groovy
def call(Map config) {
    def image = config.image
    def tag   = config.tag ?: env.BUILD_NUMBER

    docker.withRegistry('https://registry.example.com', 'registry-creds') {
        def built = docker.build("${image}:${tag}")
        built.push()
        built.push('latest')
    }
}

// Jenkinsfile in any repo
@Library('my-lib@main') _

pipeline {
    agent { label 'docker-agent' }
    stages {
        stage('Build & Push') {
            steps { buildAndPush(image: 'myapp', tag: env.GIT_COMMIT) }
        }
    }
}

pipeline {
  agent any
  environment {
    DEPLOY_TOKEN = credentials('deploy-token-id')
  }
  stages {
    stage('Deploy') {
      steps {
        withVault(vaultSecrets: [[path: 'secret/prod/db', secretValues: [
          [envVar: 'DB_PASS', vaultKey: 'password']
        ]]]) {
          sh 'deploy.sh --db-pass "$DB_PASS" --token "$DEPLOY_TOKEN"'
        }
      }
    }
  }
}

pipeline {
  agent any
  environment {
    DOCKER_BUILDKIT = '1'
    CACHE_KEY = sh(script: 'sha256sum package-lock.json | cut -d" " -f1', returnStdout: true).trim()
  }
  stages {
    stage('Restore deps') {
      steps {
        sh 'cp -r /cache/node_modules/${CACHE_KEY}/node_modules . 2>/dev/null || npm ci && mkdir -p /cache/node_modules/${CACHE_KEY} && cp -r node_modules /cache/node_modules/${CACHE_KEY}/'
      }
    }
    stage('Docker Build') {
      steps {
        sh '''
          docker build \
            --cache-from registry.example.com/myapp:cache \
            --build-arg BUILDKIT_INLINE_CACHE=1 \
            -t registry.example.com/myapp:${BUILD_NUMBER} \
            -t registry.example.com/myapp:cache .
          docker push registry.example.com/myapp:cache
        '''
      }
    }
  }
}

pipeline {
  agent none
  stages {
    stage('Matrix Test') {
      matrix {
        axes {
          axis { name 'SHARD_INDEX'; values '1','2','3' }
          axis { name 'JDK'; values '17','21' }
        }
        agent { label "jdk-${JDK}" }
        options { timeout(time: 20, unit: 'MINUTES') }
        failFast true
        stages {
          stage('Test') {
            steps {
              sh "./gradlew test -Pshard=${SHARD_INDEX} -PshardTotal=3"
            }
            post { always { junit 'build/test-results/**/*.xml' } }
          }
        }
      }
    }
  }
}

pipeline {
  agent any
  options { buildDiscarder(logRotator(artifactNumToKeepStr: '10')) }
  environment { VERSION = "${BUILD_NUMBER}-${GIT_COMMIT[0..7]}" }
  stages {
    stage('Build') {
      steps {
        sh "./gradlew build -Pversion=${VERSION}"
        archiveArtifacts artifacts: 'build/libs/*.jar', fingerprint: true
      }
    }
    stage('Promote to Staging') {
      steps {
        copyArtifacts(projectName: env.JOB_NAME, selector: specific(env.BUILD_NUMBER))
        input message: "Deploy ${VERSION} to staging?"
        sh "./deploy.sh staging build/libs/app-${VERSION}.jar"
      }
    }
  }
}

pipeline {
  agent any
  options { disableConcurrentBuilds() }
  stages {
    stage('Deploy to Staging') {
      steps {
        milestone(1)
        timeout(time: 2, unit: 'HOURS') {
          input message: 'Promote to staging?', submitter: 'dev-leads'
        }
        sh './deploy.sh staging'
      }
    }
    stage('Deploy to Prod') {
      steps {
        milestone(2)
        lock('production-environment') {
          timeout(time: 1, unit: 'HOURS') {
            input message: 'Approve prod release?', submitter: 'ops-team,release-manager'
          }
          sh './deploy.sh prod'
        }
      }
    }
  }
}

pipeline {
  agent any
  environment { IMAGE = 'myrepo/app' }
  stages {
    stage('Deploy') {
      steps {
        sh "kubectl set image deployment/app app=${IMAGE}:${BUILD_NUMBER} --record"
        sh "kubectl rollout status deployment/app --timeout=120s"
      }
    }
  }
  post {
    failure {
      script {
        def lastGood = currentBuild.previousSuccessfulBuild?.number
        if (lastGood) {
          sh "kubectl set image deployment/app app=${IMAGE}:${lastGood}"
          currentBuild.description = "ROLLED BACK to build #${lastGood}"
        } else {
          echo 'No previous successful build found ‚Äî manual intervention required.'
        }
      }
    }
  }
}

pipeline {
  agent any
  stages {
    stage('Deploy Preview') {
      when { changeRequest() }
      steps {
        sh "helm upgrade --install pr-${env.CHANGE_ID} ./chart --namespace pr-${env.CHANGE_ID} --create-namespace --set image.tag=${env.GIT_COMMIT[0..6]}"
        echo "Preview: https://pr-${env.CHANGE_ID}.preview.example.com"
      }
    }
  }
  post {
    cleanup {
      script {
        if (env.CHANGE_ID) {
          sh "helm uninstall pr-${env.CHANGE_ID} --namespace pr-${env.CHANGE_ID} || true"
          sh "kubectl delete namespace pr-${env.CHANGE_ID} --ignore-not-found"
        }
      }
    }
  }
}

pipeline {
  agent any
  stages {
    stage('Security') {
      parallel {
        stage('SAST') {
          steps {
            sh 'semgrep --config=auto --json > semgrep-report.json || true'
            recordIssues tools: [semgrep(pattern: 'semgrep-report.json')]
          }
        }
        stage('SCA') {
          steps {
            dependencyCheck additionalArguments: '--scan . --format JSON', odcInstallation: 'OWASP-DC'
            dependencyCheckPublisher pattern: '**/dependency-check-report.json'
          }
        }
        stage('Container') {
          steps {
            sh 'trivy image --exit-code 1 --severity HIGH,CRITICAL myapp:${BUILD_NUMBER}'
          }
        }
      }
    }
  }
  post {
    always {
      archiveArtifacts artifacts: '**/semgrep-report.json, **/dependency-check-report.json'
    }
  }
}

pipeline {
  agent any
  triggers { pollSCM('H/2 * * * *') }
  stages {
    stage('Reconcile') {
      when { changeset 'k8s/**' }
      steps {
        withCredentials([file(credentialsId: 'kubeconfig', variable: 'KUBECONFIG')]) {
          sh 'kubectl apply --server-side -f k8s/ --prune -l app=myservice'
        }
      }
    }
  }
}

pipeline {
  agent { label 'linux-docker' }
  stages {
    stage('Build') {
      steps {
        withCredentials([string(credentialsId: 'NPM_TOKEN', variable: 'NPM_TOKEN')]) {
          sh 'npm ci'
        }
      }
    }
    stage('Untrusted PR') {
      when { changeRequest() }
      agent { docker { image 'node:22-alpine'; reuseNode false } }
      steps {
        sh 'npm test'
      }
    }
  }
}

pipeline {
  agent any
  options { skipDefaultCheckout(true) }
  stages {
    stage('Checkout') {
      steps {
        checkout scm
      }
    }
    stage('Build & Test') {
      parallel {
        stage('Unit Tests') {
          steps { sh 'mvn -pl module-a test -o' }
        }
        stage('Integration Tests') {
          steps { sh 'mvn -pl module-b verify -o' }
        }
      }
    }
  }
  post {
    always {
      echo "Total duration: ${currentBuild.durationString}"
    }
  }
}

pipeline {
  agent any
  environment {
    AFFECTED = sh(script: 'npx turbo run build --dry=json --filter=...[HEAD^1] | jq -r ".packages[]"', returnStdout: true).trim()
  }
  stages {
    stage('Test') {
      when { expression { env.AFFECTED.contains('packages/api') } }
      steps { sh 'npx turbo run test --filter=api' }
    }
    stage('Deploy') {
      when { expression { env.AFFECTED.contains('packages/api') } }
      steps { sh './scripts/deploy.sh api' }
    }
  }
}

pipeline {
  agent any
  post {
    failure {
      script {
        def isRecurring = currentBuild.previousBuild?.result == 'FAILURE'
        if (isRecurring) {
          httpRequest(
            url: 'https://events.pagerduty.com/v2/enqueue',
            httpMode: 'POST',
            contentType: 'APPLICATION_JSON',
            requestBody: """{"routing_key":"${PAGERDUTY_KEY}","event_action":"trigger","payload":{"summary":"${JOB_NAME} failing repeatedly","severity":"critical","source":"${BUILD_URL}"}}"""
          )
        } else {
          slackSend channel: '#alerts', color: 'danger',
            message: "FAILED: ${JOB_NAME} #${BUILD_NUMBER} ‚Äî ${BUILD_URL}"
        }
      }
    }
    fixed {
      slackSend channel: '#alerts', color: 'good',
        message: "RECOVERED: ${JOB_NAME} #${BUILD_NUMBER}"
    }
  }
}
